class Cashier:
    def __init__(self, n, discount, products, prices):
        self.n = n
        self.discount = discount
        self.prices = {p: pr for p, pr in zip(products, prices)}
        self.calls = 0
    def getBill(self, product, amount):
        self.calls += 1
        total = 0
        for p, a in zip(reversed(product), reversed(amount)):
            total += self.prices[p] * a
        if self.calls % self.n == 0:
            total = total * (100 - self.discount) / 100
        return total

