class Cashier:
    def __init__(self, n: int, discount: int, products, prices):
        self.n = n
        self.discount = discount
        self.price = dict(zip(products, prices))
        self.count = 0
    def getBill(self, product, amount) -> float:
        self.count += 1
        bill = sum(self.price[p] * a for p, a in zip(product, amount))
        if self.count % self.n == 0:
            bill = bill * (100 - self.discount) / 100
        return bill

