var Cashier = function(n, discount, products, prices) {
    this.n = n;
    this.discount = discount;
    this.price = {};
    for (let i = 0; i < products.length; i++) this.price[products[i]] = prices[i];
    this.count = 0;
};
Cashier.prototype.getBill = function(product, amount) {
    this.count += 1;
    let bill = 0;
    for (let i = 0; i < product.length; i++) bill += this.price[product[i]] * amount[i];
    if (this.count % this.n === 0) {
        bill = bill * (100 - this.discount) / 100;
    }
    return bill;
};
